import './App.css';
import Navbar from './components/ui/navbar';

function Map() {
  return (
    <div style={{ width: "100%", height: "100vh" }}>
      <iframe
        src="https://www.google.com/maps/embed?pb=!1m14!1m12!1m3!1d39448.509951781474!2d-80.52416504530215!3d43.46217509205705!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!5e1!3m2!1sen!2sca!4v1757886009005!5m2!1sen!2sca"
        width="100%"
        height="100%"
        style={{ border: 0 }}
        allowFullScreen
        loading="lazy"
        referrerPolicy="no-referrer-when-downgrade"
        title="Google Map"
      ></iframe>
    </div>
  );
}

function App() {
  return (
    <div className="App">
      <Navbar />
      <header className="App-header">
        <h1>Welcome to React</h1>
      </header>
      <Map />
    </div>
  );
}

export default App;
